import React, { useState, useContext } from "react";
import { useNavigate } from "react-router-dom"; 
import Navbar from "../components/navbar";
import Axios from "axios";
import Footer from "../components/footer";
import LoginDetails from "../context/LoginContext";
import logo from "../assets/imgs/logo.png";
import "../assets/css/form.css";

const Login = () => {
	const navigate = useNavigate();
	const { setUser } = useContext(LoginDetails);
	const BASE_URL = process.env.REACT_APP_BASE_URL;

	const [credentials, setCredentials] = useState({ email: "", password: "" });
	const [error, setError] = useState("");

	const onFormSubmit = async (event) => {
		event.preventDefault();
		setError(""); // Reset error message

		// Check if fields are empty
		if (!credentials.email || !credentials.password) {
			setError("All fields are required!");
			return;
		}

		try {
			const response = await Axios.post(`${BASE_URL}/user/login`, credentials);
			const data = response.data;

			console.info("Login Response:", data);

			// Store user data
			localStorage.setItem("user", JSON.stringify(data));
			setUser(data.user);

			// Redirect based on user role
			if (data.user.role === "patient") {
				navigate("/patient");
			} else if (data.user.role === "admin") {
				navigate("/admin");
			} else {
				setError("Unauthorized user role!");
			}
		} catch (error) {
			console.error("Login Error:", error);

			// Handle different error cases
			if (error.response) {
				// Server responded with a status other than 2xx
				if (error.response.status === 401) {
					setError("Incorrect Email or Password!");
				} else if (error.response.status === 404) {
					setError("User not found. Please sign up.");
				} else {
					setError("Something went wrong! Please try again.");
				}
			} else if (error.request) {
				// No response from server
				setError("Server is not responding. Please try again later.");
			} else {
				// Something else happened
				setError("An unexpected error occurred.");
			}
		}
	};

	const toSignUp = () => {
		navigate("/signup");
	};

	return (
		<React.Fragment>
			<div id="super-container">
				<Navbar />
				<div className="parent-container">
					<form id="login-container" onSubmit={onFormSubmit}>
						<img src={logo} alt="Health Insurance" />
						<div className="input-container">
							<i className="fa fa-envelope icon"></i>
							<input
								className="logininput"
								type="email"
								name="email"
								placeholder="Email *"
								required
								value={credentials.email}
								onChange={(e) =>
									setCredentials({ ...credentials, email: e.target.value })
								}
							/>
						</div>
						<div className="input-container">
							<i className="fa fa-lock icon"></i>
							<input
								className="logininput"
								type="password"
								name="password"
								placeholder="Password *"
								required
								value={credentials.password}
								onChange={(e) =>
									setCredentials({ ...credentials, password: e.target.value })
								}
							/>
						</div>
						{error && <div id="Incorrect-credentials">{error}</div>}
						<button id="submit" type="submit">
							Login
						</button>
						<span className="spantext">Don't have an account? Create one.</span>
						<button id="lastbtn" type="button" onClick={toSignUp}>
							Sign Up
						</button>
					</form>
				</div>
			</div>
			<Footer />
		</React.Fragment>
	);
};

export default Login;
